using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public sealed class TicketClassifierService
{
    private readonly MLContext _ml = new(seed: 0);
    private readonly string _dataPath;
    private readonly string _modelPath;

    private PredictionEngine<TicketInput, TicketPrediction>? _engine;
    private string[] _categoryLabels = [];

    public TicketClassifierService(IWebHostEnvironment env)
    {
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
    }

    public bool IsModelTrained => _engine is not null;

    /// <summary>
    /// Trains the multiclass classifier and loads the prediction engine.
    /// Returns evaluation metrics computed via cross-validation.
    /// </summary>
    public EvaluationResponse TrainAndEvaluate()
    {
        var data = _ml.Data.LoadFromTextFile<TicketInput>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var pipeline = _ml.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketInput.Category))
            .Append(_ml.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketInput.Subject)))
            .Append(_ml.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(_ml.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
            .Append(_ml.Transforms.NormalizeMinMax("Features"))
            .Append(_ml.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_ml.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // Cross-validate for metrics (small dataset, so use leave-one-out-style folds)
        var cvResults = _ml.MulticlassClassification.CrossValidate(data, pipeline, numberOfFolds: 3);

        // Train final model on full data
        var model = pipeline.Fit(data);
        _ml.Model.Save(model, data.Schema, _modelPath);
        LoadPredictionEngine(model, data.Schema);

        // Aggregate CV metrics
        var best = cvResults.OrderByDescending(r => r.Metrics.MacroAccuracy).First().Metrics;

        var perClass = new List<PerClassMetrics>();
        if (best.PerClassLogLoss is not null)
        {
            for (var i = 0; i < _categoryLabels.Length && i < best.PerClassLogLoss.Count; i++)
            {
                perClass.Add(new PerClassMetrics(
                    _categoryLabels[i],
                    Precision: 0,   // detailed per-class P/R requires manual confusion-matrix work
                    Recall: 0,
                    F1Score: 0));
            }
        }

        return new EvaluationResponse(
            MacroAccuracy: best.MacroAccuracy,
            MicroAccuracy: best.MicroAccuracy,
            LogLoss: best.LogLoss,
            LogLossReduction: best.LogLossReduction,
            PerClassMetrics: perClass.ToArray());
    }

    /// <summary>
    /// Returns detailed per-class evaluation on the full training set.
    /// </summary>
    public EvaluationResponse Evaluate()
    {
        if (!File.Exists(_modelPath))
            throw new InvalidOperationException("Model has not been trained yet. POST /api/tickets/train first.");

        var data = _ml.Data.LoadFromTextFile<TicketInput>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);
        var model = _ml.Model.Load(_modelPath, out _);
        var predictions = model.Transform(data);

        var metrics = _ml.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        var confusionMatrix = metrics.ConfusionMatrix;
        var perClass = new List<PerClassMetrics>();
        for (var i = 0; i < confusionMatrix.PerClassPrecision.Count; i++)
        {
            perClass.Add(new PerClassMetrics(
                i < _categoryLabels.Length ? _categoryLabels[i] : $"Class{i}",
                confusionMatrix.PerClassPrecision[i],
                confusionMatrix.PerClassRecall[i],
                F1Score: 2 * confusionMatrix.PerClassPrecision[i] * confusionMatrix.PerClassRecall[i]
                         / (confusionMatrix.PerClassPrecision[i] + confusionMatrix.PerClassRecall[i]
                            + double.Epsilon)));
        }

        return new EvaluationResponse(
            metrics.MacroAccuracy,
            metrics.MicroAccuracy,
            metrics.LogLoss,
            metrics.LogLossReduction,
            perClass.ToArray());
    }

    public PredictResponse Predict(PredictRequest request)
    {
        if (_engine is null)
            throw new InvalidOperationException("Model has not been trained yet. POST /api/tickets/train first.");

        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _engine.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (var i = 0; i < _categoryLabels.Length && i < prediction.Score.Length; i++)
            confidence[_categoryLabels[i]] = prediction.Score[i];

        return new PredictResponse(prediction.Category, confidence);
    }

    /// <summary>
    /// Attempts to load a previously saved model on startup.
    /// </summary>
    public void TryLoadModel()
    {
        if (!File.Exists(_modelPath)) return;

        var model = _ml.Model.Load(_modelPath, out var schema);
        LoadPredictionEngine(model, schema);
    }

    private void LoadPredictionEngine(ITransformer model, DataViewSchema schema)
    {
        _engine = _ml.Model.CreatePredictionEngine<TicketInput, TicketPrediction>(model);

        // Extract label names from the key-value metadata
        var labelCol = model.GetOutputSchema(schema)["PredictedLabel"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();

        // Labels are stored as metadata on the "Label" column
        var labelKeyCol = model.GetOutputSchema(schema)["Label"];
        labelKeyCol.GetKeyValues(ref slotNames);
        _categoryLabels = slotNames.DenseValues().Select(v => v.ToString()).ToArray();
    }
}

