namespace TicketClassifier.Models;

public sealed record PredictRequest(string Subject, string Description, int Priority);

public sealed record PredictResponse(
    string PredictedCategory,
    Dictionary<string, float> Confidence);

public sealed record EvaluationResponse(
    double MacroAccuracy,
    double MicroAccuracy,
    double LogLoss,
    double LogLossReduction,
    PerClassMetrics[] PerClassMetrics);

public sealed record PerClassMetrics(string Category, double Precision, double Recall, double F1Score);

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public sealed class TicketsController(TicketClassifierService classifier) : ControllerBase
{
    /// <summary>
    /// POST /api/tickets/train — Trains the model and returns evaluation metrics.
    /// </summary>
    [HttpPost("train")]
    public ActionResult<EvaluationResponse> Train()
    {
        var metrics = classifier.TrainAndEvaluate();
        return Ok(metrics);
    }

    /// <summary>
    /// GET /api/tickets/evaluate — Returns evaluation metrics for the current model.
    /// </summary>
    [HttpGet("evaluate")]
    public ActionResult<EvaluationResponse> Evaluate()
    {
        try
        {
            return Ok(classifier.Evaluate());
        }
        catch (InvalidOperationException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
    }

    /// <summary>
    /// POST /api/tickets/predict — Predicts the category for a support ticket.
    /// </summary>
    [HttpPost("predict")]
    public ActionResult<PredictResponse> Predict([FromBody] PredictRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject))
            return BadRequest(new { error = "Subject is required." });

        if (request.Priority is < 1 or > 3)
            return BadRequest(new { error = "Priority must be between 1 and 3." });

        try
        {
            return Ok(classifier.Predict(request));
        }
        catch (InvalidOperationException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
    }
}

